const bridgeOutput = $input.first().json;

if (bridgeOutput.output && bridgeOutput.output.length > 10) {
  return [{ json: { output: bridgeOutput.output, elapsed_s: bridgeOutput.elapsed_s || 0, fallback: false, prompt: '' } }];
}

const prompt = $('Build Diagnostic Prompt + Memory').first().json.prompt || '';
return [{ json: { output: '', elapsed_s: 0, fallback: true, prompt: prompt } }];

const response = $input.first().json;
const text = response.content && response.content[0] ? response.content[0].text : JSON.stringify(response);
return [{ json: { output: text + '\n\n⚠️ Gerado via Haiku API (fallback — Claude Bridge indisponivel)', elapsed_s: 0 } }];
